inputs.Script:
$inputPayload = $env:InputPayload | ConvertFrom-Json
$instanceMappings = $inputPayload.mappedDevices

function Get-DeviceList {
foreach ($letterMapping in 98..122) {
if (-not ($instanceMappings -match "sd$([char]$letterMapping)" -or $instanceMappings -match "xvd$([char]$letterMapping)")) {
return "xvd$([char]$letterMapping)"
}
}
}
$availableDevice = Get-DeviceList

if (-not $availableDevice) {
Write-Host "ERROR: No free device available."
Exit 1
}
else {
return @{availableDevice = "$availableDevice" }
Exit 0
}
